class Solution {
public:
    int nextBeautifulNumber(int n) {
        while (true) {
            n++;
            string s = to_string(n);
            bool balanced = true;
            int count[10] = {0};
            for (char c : s) {
                int digit = c - '0';
                count[digit]++;
                if (count[digit] != digit) {
                    balanced = false;
                    break;
                }
            }
            if (balanced) return n;
        }
    }
};
```
